import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface VaccinationStatus {
  dosesReceived: number;
  nextDueDate: string;
  coveragePercentage: number;
}

interface DoseHistory {
  dose: number;
  date: string;
}

interface VaccinationData {
  vaccinationStatus: VaccinationStatus;
  doseHistory: DoseHistory[];
  coverageTrend: number[];
}

export default function Widget() {
  const vaccinationData = response.data as VaccinationData;
  const { vaccinationStatus, doseHistory, coverageTrend } = vaccinationData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#4CAF50' }}>
              Vaccination Tracker
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Doses Received: {vaccinationStatus.dosesReceived}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Next Due Date: {vaccinationStatus.nextDueDate}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Coverage: {vaccinationStatus.coveragePercentage}%
            </Typography>
          </Box>

          <Box>
            <Typography variant="caption" color="text.secondary" sx={{ mb: 1 }}>
              Dose History
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {doseHistory.map((dose) => (
                <Chip
                  key={dose.dose}
                  label={`Dose ${dose.dose}: ${dose.date}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: coverageTrend,
                  color: '#FFC107',
                  label: 'Coverage Trend',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: coverageTrend.map((_, i) => i),
                },
              ]}
              yAxis={[
                {
                  id: 'coverage',
                },
              ]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="coverage"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
